class Solution:
    def closestPrimes(self, left, right):
        def is_p(n):
            if n < 2:
                return False
            i = 2
            while i * i <= n:
                if n % i == 0:
                    return False
                i += 1
            return True
        primes = [n for n in range(left, right + 1) if is_p(n)]
        best = [-1, -1]
        best_diff = float('inf')
        for i in range(1, len(primes)):
            d = primes[i] - primes[i - 1]
            if d < best_diff:
                best_diff = d
                best = [primes[i - 1], primes[i]]
        return best

