class Solution:
    def closestPrimes(self, left, right):
        is_prime = [True] * (right + 1)
        if right >= 0:
            is_prime[0] = False
        if right >= 1:
            is_prime[1] = False
        i = 2
        while i * i <= right:
            if is_prime[i]:
                for j in range(i * i, right + 1, i):
                    is_prime[j] = False
            i += 1
        primes = [n for n in range(max(2, left), right + 1) if is_prime[n]]
        best = [-1, -1]
        best_diff = float('inf')
        for idx in range(1, len(primes)):
            diff = primes[idx] - primes[idx - 1]
            if diff < best_diff:
                best_diff = diff
                best = [primes[idx - 1], primes[idx]]
        return best

