var closestPrimes = function(left, right) {
    const isPrime = new Array(right + 1).fill(true);
    if (right >= 0) isPrime[0] = false;
    if (right >= 1) isPrime[1] = false;
    for (let i = 2; i * i <= right; i++) {
        if (isPrime[i]) {
            for (let j = i * i; j <= right; j += i) isPrime[j] = false;
        }
    }
    const primes = [];
    for (let n = Math.max(2, left); n <= right; n++) {
        if (isPrime[n]) primes.push(n);
    }
    let best = [-1, -1];
    let bestDiff = Infinity;
    for (let idx = 1; idx < primes.length; idx++) {
        const diff = primes[idx] - primes[idx - 1];
        if (diff < bestDiff) {
            bestDiff = diff;
            best = [primes[idx - 1], primes[idx]];
        }
    }
    return best;
};
